chrome.runtime.onInstalled.addListener(()=>{console.log("Workday AI Autofill Extension Installed"),chrome.sidePanel.setPanelBehavior({openPanelOnActionClick:!0}).catch(e=>console.error(e))});chrome.runtime.onMessage.addListener((e,t,o)=>{if(e.action==="API_CALL")return fetch(`https://workday-ai-backend.onrender.com/${e.endpoint}`,{method:e.method||"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(e.payload)}).then(n=>n.json()).then(n=>o({success:!0,data:n})).catch(n=>o({success:!1,error:n.message})),!0});
